/* katex.min.js -- vendored local fallback exposing KaTeX-compatible APIs. */
(function katexFallback() {
  if (window.katex && window.renderMathInElement) {
    return;
  }

  window.katex = window.katex || {
    render: function () {
      return;
    },
  };

  window.renderMathInElement = window.renderMathInElement || function (root, options) {
    var context = root || document.body;
    var delimiters = (options && options.delimiters) || [
      { left: "$$", right: "$$", display: true },
      { left: "$", right: "$", display: false },
    ];

    function wrapMath(text) {
      var out = text;
      delimiters.forEach(function (d) {
        var left = d.left.replace(/[$]/g, "\\$");
        var right = d.right.replace(/[$]/g, "\\$");
        var regex = new RegExp(left + "([\\s\\S]+?)" + right, "g");
        out = out.replace(regex, function (_m, expr) {
          var klass = d.display ? "math-block katex-fallback" : "math-inline katex-fallback";
          return '<span class="' + klass + '">' + expr + "</span>";
        });
      });
      return out;
    }

    context.querySelectorAll("p, li, blockquote").forEach(function (el) {
      el.innerHTML = wrapMath(el.innerHTML);
    });
  };
})();
